import torch

def compress(g, v, i):
    n = g.shape[0]
    out = torch.zeros(i, dtype=v.dtype)
    pos = 0
    for k in range(n):
        if g[k] != 0:
            if pos < i:
                out[pos] = v[k]
                pos += 1
    return out

